mapper.select:
SELECT o.*, p.title AS product_title, p.cover_img AS product_cover_img, seller.nickname AS seller_name, buyer.nickname AS buyer_name FROM trade_order o LEFT JOIN product p ON o.product_id = p.id LEFT JOIN sys_user seller ON o.seller_id = seller.id LEFT JOIN sys_user buyer ON o.buyer_id = buyer.id WHERE 1=1
AND o.buyer_id = #{userId}
AND o.seller_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
